// Green Vibes — utils/storage.js
// Persistance : saveData, loadData, import, export
// Dépend de : APP (global)
// ========== PERSISTENCE ==========
const DATA_VERSION = '1.0';

function saveData() {
  try {
    const data = getAppStateDeep();
    localStorage.setItem('gvp_data', JSON.stringify({ version: DATA_VERSION, data: data }));
  } catch(e) {
    console.error('Erreur sauvegarde:', e);
  }
}

function loadData() {
  try {
    const raw = localStorage.getItem('gvp_data');
    if (raw) {
      const stored = JSON.parse(raw);
      let d = stored.data || stored; // Support anciennes versions sans version

      // Migration si version ancienne
      if (!stored.version || stored.version !== DATA_VERSION) {
        d = migrateData(d, stored.version || '0.0');
      }

      // Fusionner avec valeurs par défaut
      Object.keys(d).forEach(key => updateAppState(key, d[key]));
      if (!getAppState('vegetables') || Object.keys(getAppState('vegetables')).length === 0) {
        updateAppState('vegetables', JSON.parse(JSON.stringify(DEFAULT_VEGETABLES)));
      } else {
        // Ajouter les nouveaux légumes du référentiel aux utilisateurs existants
        var savedVegs = getAppState('vegetables');
        var newAdded = false;
        Object.keys(DEFAULT_VEGETABLES).forEach(function(id) {
          if (!savedVegs[id]) {
            savedVegs[id] = JSON.parse(JSON.stringify(DEFAULT_VEGETABLES[id]));
            newAdded = true;
          }
        });
        if (newAdded) { updateAppState('vegetables', savedVegs); }
      }
      if (!getAppState('location') || !getAppState('location').lat) {
        updateAppState('location', { lat: 48.8566, lon: 2.3522, name: 'Paris' });
      }
      if (!getAppState('completedTasks')) updateAppState('completedTasks', []);
      if (!getAppState('seasons') || !getAppState('seasons').length) updateAppState('seasons', ['2026']);
      if (!getAppState('currentSeason')) updateAppState('currentSeason', '2026');
      if (!getAppState('beds')) updateAppState('beds', []);
      if (!getAppState('crops')) updateAppState('crops', []);
      if (!getAppState('settings')) updateAppState('settings', { theme: 'default', languageChosen: false });
      // Migration: existing users (with beds or crops) skip the language picker
      var _st = getAppState('settings');
      if (_st && !_st.veggieFavorites) { _st.veggieFavorites = []; updateAppState('settings', _st); }
      if (_st && _st.languageChosen === undefined) {
        var _hasBeds = (getAppState('beds') || []).length > 0;
        var _hasCrops = (getAppState('crops') || []).length > 0;
        _st.languageChosen = _hasBeds || _hasCrops;
        updateAppState('settings', _st);
      }
      if (!getAppState('language')) updateAppState('language', 'fr');
      if (!getAppState('userProfile')) updateAppState('userProfile', { name:'', level:'', spaceType:'', goals:[], onboardingDone:false });
      if (!getAppState('notificationsRead')) updateAppState('notificationsRead', []);
      if (!getAppState('notificationsIgnored')) updateAppState('notificationsIgnored', []);
    } else {
      updateAppState('vegetables', JSON.parse(JSON.stringify(DEFAULT_VEGETABLES)));
      updateAppState('beds', []);
      updateAppState('crops', []);
      updateAppState('seasons', ['2026']);
      updateAppState('currentSeason', '2026');
      updateAppState('location', { lat: 48.8566, lon: 2.3522, name: 'Paris' });
      updateAppState('completedTasks', []);
      updateAppState('settings', { theme: 'default', languageChosen: false });
      updateAppState('language', 'fr');
      updateAppState('userProfile', { name:'', level:'', spaceType:'', goals:[], onboardingDone:false });
      updateAppState('notificationsRead', []);
      updateAppState('notificationsIgnored', []);
    }
    // Correction automatique des statuts planned / active
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    let migrated = false;
    getAppState('crops').forEach(function(crop) {
      if (!crop || crop.status === 'harvested') return;
      if (!crop.startType) { crop.startType = 'plant'; migrated = true; }
      if (!crop.datePlant) return;
      const plantDate = new Date(crop.datePlant);
      if (isNaN(plantDate.getTime())) return;
      plantDate.setHours(0, 0, 0, 0);
      const newStatus = plantDate > today ? 'planned' : 'active';
      if (crop.status !== newStatus) { crop.status = newStatus; migrated = true; }
    });
    if (migrated) saveData();
  } catch (e) {
    console.error('Erreur chargement:', e);
    updateAppState('vegetables', JSON.parse(JSON.stringify(DEFAULT_VEGETABLES)));
    updateAppState('beds', []);
    updateAppState('crops', []);
    updateAppState('seasons', ['2026']);
    updateAppState('currentSeason', '2026');
    updateAppState('location', { lat: 48.8566, lon: 2.3522, name: 'Paris' });
    updateAppState('completedTasks', []);
    updateAppState('settings', { theme: 'default' });
  }
}

// ========== MIGRATION ==========
function migrateData(data, fromVersion) {
  if (parseFloat(fromVersion) < 1.0) {
    // Ajouter champ manquant si nécessaire
    if (!data.notificationsRead) data.notificationsRead = [];
    if (!data.notificationsIgnored) data.notificationsIgnored = [];
  }
  return data;
}

function cleanOrphanVeggies() {
  // Supprimer les cultures qui référencent un légume supprimé (ex: v46 Pois gourmand)
  var crops = getAppState('crops');
  var vegetables = getAppState('vegetables');
  var cleaned = crops.filter(function(c) { return c && vegetables[c.veggieId]; });
  if (cleaned.length !== crops.length) {
    updateAppState('crops', cleaned);
  }
}

function genId() { return 'id_' + Date.now() + '_' + Math.random().toString(36).slice(2, 7); }
;
// Green Vibes — utils/weather.js
// Météo : fetchWeather, getWeatherEmoji, getWeatherAlerts, renderWeatherWidget
// Dépend de : APP, escH
// ========== WEATHER ==========
async function fetchWeather() {
  var now = Date.now();
  if (getAppState('weather') && getAppState('weatherLastFetch') && (now - getAppState('weatherLastFetch') < 30 * 60 * 1000)) return getAppState('weather');
  try {
    var _loc = getAppState('location');
    if (!_loc || typeof _loc.lat !== 'number') return null;
    var lat = _loc.lat;
    var lon = _loc.lon;
    var url = 'https://api.open-meteo.com/v1/forecast?latitude=' + lat + '&longitude=' + lon +
      '&current=temperature_2m,relative_humidity_2m,wind_speed_10m,precipitation,weather_code' +
      '&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,weather_code&timezone=auto&forecast_days=7';
    var resp = await fetch(url);
    if (!resp.ok) throw new Error('Weather API error');
    var data = await resp.json();
    updateAppState('weather', data);
    updateAppState('weatherLastFetch', now);
    return data;
  } catch(e) {
    console.error('Erreur meteo:', e);
    // Afficher un message d'erreur visible
    if (document.getElementById('pageDashboard')) {
      var el = document.getElementById('pageDashboard');
      el.innerHTML += '<div style="margin:10px;padding:10px;background:#fee;border-radius:10px;color:#c33;">' + t('wx_error') + '</div>';
    }
    return null;
  }
}
function getWeatherEmoji(code) {
  if (code === 0) return '☀️';
  if (code <= 3) return '⛅';
  if (code <= 48) return '🌫️';
  if (code <= 55) return '🌦️';
  if (code <= 65) return '🌧️';
  if (code <= 67) return '🌧️';
  if (code <= 75) return '❄️';
  if (code <= 77) return '❄️';
  if (code <= 82) return '🌧️';
  if (code <= 86) return '🌨️';
  if (code >= 95) return '⛈️';
  return '🌤️';
}
function getWeatherDesc(code) {
  if (code === 0) return t('wx_clear');
  if (code <= 3) return t('wx_partly_cloudy');
  if (code <= 48) return t('wx_foggy');
  if (code <= 55) return t('wx_drizzle');
  if (code <= 65) return t('wx_rain');
  if (code <= 67) return t('wx_freezing_rain');
  if (code <= 75) return t('wx_snow');
  if (code <= 77) return t('wx_snow_grains');
  if (code <= 82) return t('wx_showers');
  if (code <= 86) return t('wx_snow_showers');
  if (code >= 95) return t('wx_storm');
  return t('wx_variable');
}
function getDayName(dateStr) {
  var d = new Date(dateStr + 'T12:00:00');
  return t('day_s_' + d.getDay());
}
function getWeatherAlerts(weather) {
  if (!weather || !weather.current) return [];
  var alerts = [];
  var temp = weather.current.temperature_2m;
  var w = weather.current.wind_speed_10m;
  var p = weather.current.precipitation;
  if (temp <= 2) alerts.push({ icon: '🥶', text: t('alert_frost') + ' ' + temp + '\u00B0C', type: 'danger' });
  else if (temp <= 5) alerts.push({ icon: '❄️', text: t('alert_cold') + ' ' + temp + '\u00B0C', type: 'warning' });
  if (temp >= 35) alerts.push({ icon: '🔥', text: t('alert_heat') + ' ' + temp + '\u00B0C', type: 'danger' });
  else if (temp >= 30) alerts.push({ icon: '☀️', text: t('alert_warm') + ' ' + temp + '\u00B0C', type: 'warning' });
  if (p > 10) alerts.push({ icon: '🌊', text: t('alert_heavy_rain') + ' ' + p + 'mm', type: 'danger' });
  else if (p > 5) alerts.push({ icon: '🌧️', text: t('alert_rain_lbl') + ' ' + p + 'mm', type: 'warning' });
  if (w > 50) alerts.push({ icon: '💨', text: t('alert_strong_wind') + ' ' + w + 'km/h', type: 'danger' });
  else if (w > 30) alerts.push({ icon: '🌬️', text: t('alert_moderate_wind') + ' ' + w + 'km/h', type: 'warning' });
  return alerts;
}
function renderWeatherWidget(weather) {
  if (!weather || !weather.current) {
    return '<div class="weather-offline">' +
      '<div style="font-size:2rem;margin-bottom:8px;">📡</div>' +
      '<div>' + t('wx_offline_mode') + '</div></div>';
  }
  var c = weather.current;
  var emoji = getWeatherEmoji(c.weather_code);
  var desc = getWeatherDesc(c.weather_code);
  var alerts = getWeatherAlerts(weather);
  var forecastHTML = '';
  if (weather.daily) {
    for (var i = 0; i < Math.min(7, weather.daily.time.length); i++) {
      forecastHTML += '<div class="forecast-day">' +
        '<div>' + (i === 0 ? t('wx_today') : getDayName(weather.daily.time[i])) + '</div>' +
        '<div style="font-size:1.2rem;">' + getWeatherEmoji(weather.daily.weather_code[i]) + '</div>' +
        '<div class="f-temp">' + Math.round(weather.daily.temperature_2m_max[i]) + '\u00B0</div>' +
        '<div style="opacity:0.7">' + Math.round(weather.daily.temperature_2m_min[i]) + '\u00B0</div>' +
        '</div>';
    }
  }
  var alertsHTML = '';
  if (alerts.length > 0) {
    alertsHTML = '<div class="weather-alerts">';
    for (var j = 0; j < alerts.length; j++) {
      alertsHTML += '<div class="weather-alert">' + alerts[j].icon + ' ' + alerts[j].text + '</div>';
    }
    alertsHTML += '</div>';
  }
  return '<div class="weather-widget">' +
    '<div class="weather-location">📍 ' + escH(getAppState('location').name || 'Paris') + '</div>' +
    '<div class="weather-main">' +
      '<div class="weather-temp">' + Math.round(c.temperature_2m) + '\u00B0C</div>' +
      '<div><div class="weather-icon">' + emoji + '</div>' +
      '<div style="font-size:0.8rem;margin-top:2px;">' + desc + '</div></div>' +
    '</div>' +
    '<div class="weather-details">' +
      '<div class="weather-detail">💧 ' + c.relative_humidity_2m + '%</div>' +
      '<div class="weather-detail">💨 ' + Math.round(c.wind_speed_10m) + ' km/h</div>' +
      '<div class="weather-detail">🌧️ ' + c.precipitation + ' mm</div>' +
    '</div>' +
    '<div class="weather-forecast">' + forecastHTML + '</div>' +
    alertsHTML +
  '</div>';
}
