// RÔLE    : Persistance de l'historique des récoltes (gvp_history).
// DÉPEND  : learning-memory.js (rebuildLearningMemory),
//           utils/calculations.js (getCropEstimatedYield),
//           core.js (getAppState, genId)
// GÈRE    : loadHistory, saveHistory, addHistoryEntry,
//           pruneOrphanHistory, getMergedHarvestData
// NE GÈRE PAS : mémoire d'apprentissage, calculs stats, rendu HTML
//
// Format localStorage : { version: '1.0', data: entries[] }
// Migration automatique si version différente.
// ============================================================

var HISTORY_KEY = 'gvp_history';
const HISTORY_VERSION = '1.0';

/** Charger l'historique depuis localStorage. */
function loadHistory() {
  try {
    var raw = localStorage.getItem(HISTORY_KEY);
    if (raw) {
      var stored = JSON.parse(raw);
      if (!stored.version || stored.version !== HISTORY_VERSION) {
        stored.data = migrateHistoryData(stored.data || stored, stored.version || '0.0');
        stored.version = HISTORY_VERSION;
        saveHistory(stored.data);
      }
      return stored.data;
    }
    return [];
  } catch (e) {
    console.error('loadHistory:', e);
    return [];
  }
}

/** Sauvegarder l'historique en localStorage. */
function saveHistory(entries) {
  try {
    localStorage.setItem(HISTORY_KEY, JSON.stringify({ version: HISTORY_VERSION, data: entries }));
  } catch (e) {
    console.error('saveHistory:', e);
  }
}

/** Migration pour historique. */
function migrateHistoryData(data, fromVersion) {
  if (fromVersion < '1.0') {
    data.forEach(function(entry) {
      if (!entry.weather) entry.weather = null;
    });
  }
  return data;
}

/** Ajouter une entree d'historique. */
function addHistoryEntry(crop, realYield, weatherContext) {
  var history = loadHistory();
  var entry = {
    id: genId(),
    cropId: crop.id,
    vegetableId: crop.veggieId,
    bedId: crop.bedId,
    season: crop.season,
    date: new Date().toISOString().split('T')[0],
    realYield: realYield,
    estimatedYield: getCropEstimatedYield(crop),
    durationDays: crop.datePlant ? Math.floor((new Date() - new Date(crop.datePlant)) / 86400000) : null,
    weather: weatherContext,
    notes: crop.notes || ''
  };
  history.push(entry);
  saveHistory(history);
  // Reconstruire la memoire d'apprentissage
  rebuildLearningMemory();
}

/** Supprimer les entrees orphelines (crops supprimes). */
function pruneOrphanHistory() {
  var history = loadHistory();
  var cropIds = getAppState('crops').map(function(c){ return c.id; });
  var pruned = history.filter(function(h){ return cropIds.includes(h.cropId); });
  if (pruned.length !== history.length) {
    saveHistory(pruned);
  }
}

/** Fusionner historique + crops actifs pour analyse. */
function getMergedHarvestData() {
  var history = loadHistory();
  var active = getAppState('crops').filter(function(c){ return c.status === 'harvested'; }).map(function(c){
    return {
      id: c.id,
      cropId: c.id,
      vegetableId: c.veggieId,
      bedId: c.bedId,
      season: c.season,
      date: c.dateHarvest || new Date().toISOString().split('T')[0],
      realYield: c.realYield || 0,
      estimatedYield: getCropEstimatedYield(c),
      durationDays: c.datePlant ? Math.floor((new Date(c.dateHarvest || new Date()) - new Date(c.datePlant)) / 86400000) : null,
      weather: null, // pas dispo pour actifs
      notes: c.notes || ''
    };
  });
  return history.concat(active);
};
// Green Vibes — modules/learning-calculations.js
// ============================================================
// RÔLE    : Calculs purs sur les données d'apprentissage.
// DÉPEND  : learning-memory.js (getLearningMemory),
//           learning-history.js (getMergedHarvestData)
// GÈRE    : ratios performance, moyennes, patterns, score jardin,
//           progression saisonnière
// NE GÈRE PAS : persistance, rendu HTML, notifications, profil user
// ============================================================

/** Ratio performance d'une entree. */
function entryPerformanceRatio(entry) {
  if (!entry || entry.estimatedYield <= 0) return null;
  return entry.realYield / entry.estimatedYield;
}

/** Moyenne performance par legume. */
function avgPerformanceByVegetable(vegetableId) {
  var data = getMergedHarvestData();
  var entries = data.filter(function(e){ return e.vegetableId === vegetableId; });
  var ratios = entries.map(entryPerformanceRatio).filter(function(r){ return r !== null; });
  return ratios.length > 0 ? ratios.reduce(function(s,r){ return s+r; },0)/ratios.length : 0;
}

/** Moyenne performance par bac. */
function avgPerformanceByBed(bedId) {
  var data = getMergedHarvestData();
  var entries = data.filter(function(e){ return e.bedId === bedId; });
  var ratios = entries.map(entryPerformanceRatio).filter(function(r){ return r !== null; });
  return ratios.length > 0 ? ratios.reduce(function(s,r){ return s+r; },0)/ratios.length : 0;
}

/** Score jardin ameliore avec meteo. */
function computeEnhancedGardenScore(weather) {
  var mem = getLearningMemory();
  var baseScore = (mem.globalStats.avgRatio || 0) * 100;
  var weatherBonus = 0;
  if (weather && weather.current) {
    var temp = weather.current.temperature_2m;
    var rain = weather.current.precipitation;
    if (temp >= 15 && temp <= 25) weatherBonus += 10;
    if (rain < 5) weatherBonus += 5;
  }
  return Math.min(100, baseScore + weatherBonus);
}

/** Detecter patterns ameliores. */
function detectEnhancedPatterns() {
  var mem = getLearningMemory();
  var patterns = [];
  // Pattern 1: Legumes en hausse
  Object.keys(mem.vegetableProfiles).forEach(function(vid) {
    var p = mem.vegetableProfiles[vid];
    if (p.trend === 'hausse' && p.count >= 3) {
      patterns.push({
        type: 'vegetable_improvement',
        vegetableId: vid,
        message: t('pat_improve_title').replace('{name}', tVeg(p.name)) + ' (' + (p.avgRatio * 100).toFixed(0) + '%)',
      });
    }
  });
  // Pattern 2: Bacs sous-performants
  Object.keys(mem.bedProfiles).forEach(function(bid) {
    var p = mem.bedProfiles[bid];
    if (p.avgRatio < 0.8 && p.count >= 2) {
      patterns.push({
        type: 'bed_underperformance',
        bedId: bid,
        message: t('pat_low_bed_title').replace('{name}', p.name) + ' (' + (p.avgRatio * 100).toFixed(0) + '%)'
      });
    }
  });
  return patterns;
}

/** Donnees progression saisonniere. */
function getSeasonProgressionData() {
  var mem = getLearningMemory();
  return mem.progressionHistory;
};
// Green Vibes — modules/learning-render.js
// ============================================================
// RÔLE    : Rendu HTML des blocs d'apprentissage (progression,
//           insights actionnables).
// DÉPEND  : learning-memory.js (getLearningMemory),
//           learning-calculations.js (detectEnhancedPatterns)
// GÈRE    : buildProgressionBlock, buildActionableInsightBlock
// NE GÈRE PAS : persistance, calculs métier, notifications
//
// Schéma progressionHistory attendu (depuis rebuildLearningMemory) :
//   { season, count, totalReal, ratio }
// ============================================================

/** Bloc progression saisonniere. */
function buildProgressionBlock() {
  var mem = getLearningMemory();
  var prog = mem.progressionHistory;
  if (!prog || prog.length < 2) return '<div class="insight-card"><p>' + t('lrn_prog_no_data') + '</p></div>';
  var latest = prog[prog.length - 1];
  var prev = prog[prog.length - 2];
  var diff = (latest.ratio || 0) - (prev.ratio || 0);
  var trendIcon = diff > 0.05 ? '📈' : diff < -0.05 ? '📉' : '➡️';
  var trendText = diff > 0.05 ? t('lrn_prog_up') : diff < -0.05 ? t('lrn_prog_down') : t('lrn_prog_stable');
  return '<div class="insight-card">' +
    '<h4>' + trendIcon + ' ' + t('lrn_prog_title_section') + '</h4>' +
    '<p>' + t('lrn_prog_season_row').replace('{s}', latest.season).replace('{pct}', ((latest.ratio || 0) * 100).toFixed(0)) + '</p>' +
    '<p>' + t('lrn_prog_vs_prev').replace('{trend}', trendText).replace('{prev}', prev.season).replace('{diff}', (diff * 100).toFixed(1)) + '</p>' +
    '<p>' + t('lrn_prog_total_row').replace('{n}', (latest.count || 0)).replace('{kg}', (latest.totalReal || 0).toFixed(1)) + '</p>' +
  '</div>';
}

/** Bloc insights actionnables. */
function buildActionableInsightBlock() {
  var patterns = detectEnhancedPatterns();
  if (patterns.length === 0) return '<div class="insight-card"><p>' + t('lrn_insights_none') + '</p></div>';
  var html = '<div class="insight-card"><h4>' + t('lrn_insights_title') + '</h4><ul>';
  patterns.forEach(function(p) {
    html += '<li>' + (p.title ? p.title + (p.text ? ' — ' + p.text : '') : (p.message || '')) + '</li>';
  });
  html += '</ul></div>';
  return html;
}
