// ============================================================
// RÔLE    : Socle applicatif — doit être chargé EN DERNIER.
// GÈRE    : état global (_APP + accesseurs), navigation,
//           dispatch de rendu (renderPage), système de modales,
//           séquence d'initialisation (loadData → init → navigate)
// DÉPEND  : tous les modules (chargés avant via index.html)
// NE GÈRE PAS : logique métier, rendu de pages, météo, persistance
// ============================================================
// ========== APP STATE ==========
let _APP = {
  vegetables: {},
  beds: [],
  crops: [],
  seasons: ['2026'],
  currentSeason: '2026',
  location: { lat: 48.8566, lon: 2.3522, name: 'Paris' },
  weather: null,
  weatherLastFetch: null,
  climate: null,
  completedTasks: [],
  settings: { theme: 'default', languageChosen: false },
  language: 'fr',
  userProfile: { name: '', level: '', spaceType: '', goals: [], onboardingDone: false },
  notificationsRead: [],
  notificationsIgnored: []
};

// ========== APP STATE ACCESSORS ==========
function getAppState(key) {
  return _APP[key];
}

function updateAppState(key, value) {
  _APP[key] = value;
  // Sauvegarde automatique pour clés critiques
  if (['vegetables', 'beds', 'crops', 'seasons', 'currentSeason', 'location', 'settings', 'language', 'userProfile', 'notificationsRead', 'notificationsIgnored', 'climate'].includes(key)) {
    saveData();
  }
}

function getAppStateDeep() {
  return JSON.parse(JSON.stringify(_APP));
}

// Pour compatibilité, exposer APP en lecture seule (mais encourager getAppState)
// FRAGILITÉ : APP.xxx = value écrit directement sur _APP sans passer par updateAppState
// → pas de persistance, pas de dispatch. Toujours utiliser updateAppState() pour écrire.
const APP = new Proxy(_APP, {
  get(target, prop) { return target[prop]; },
  set(target, prop, value) { target[prop] = value; return true; }
});
let currentPage = 'dashboard';
let detailView = null;
var currentPlanningFilter = 'today';
// ========== NAVIGATION ==========
function togglePlusMenu() {
  var overlay = document.getElementById('plusOverlay');
  overlay.classList.toggle('open');
  var hbg = document.getElementById('headerHamburger');
  if (hbg) hbg.classList.toggle('active', overlay.classList.contains('open'));
}
function closePlusMenu(e) {
  if (e.target === document.getElementById('plusOverlay')) {
    document.getElementById('plusOverlay').classList.remove('open');
    var hbg = document.getElementById('headerHamburger');
    if (hbg) hbg.classList.remove('active');
  }
}
function navigateFromPlus(page) {
  document.getElementById('plusOverlay').classList.remove('open');
  var hbg = document.getElementById('headerHamburger');
  if (hbg) hbg.classList.remove('active');
  navigate(page);
}
function navigate(page, push) {
  if (push === undefined) push = true;
  // Fermer le menu hamburger si ouvert
  var overlay = document.getElementById('plusOverlay');
  if (overlay) overlay.classList.remove('open');
  var hbg = document.getElementById('headerHamburger');
  if (hbg) hbg.classList.remove('active');
  // Nettoyer les overlays flottants (onboarding, langue) et le verrou de scroll
  var _ov;
  _ov = document.getElementById('onbOverlay');       if (_ov) _ov.remove();
  _ov = document.getElementById('langPickerOverlay'); if (_ov) _ov.remove();
  document.body.style.overflow = '';
  // Fermer la modale si ouverte (évite le verrou de scroll résiduel)
  // Mais pas si elle vient juste d'être ouverte (ghost click mobile)
  var modalOv = document.getElementById('modalOverlay');
  if (modalOv && (Date.now() - _modalOpenTime > 600)) modalOv.classList.remove('active');
  currentPage = page;
  detailView = null;
  // Mode plein écran jardin sur mobile : masque header + bottom-nav
  document.body.classList.toggle('gd-garden-active', page === 'garden');
  document.querySelectorAll('.page').forEach(function(p) { p.classList.remove('active'); });
  document.querySelectorAll('.nav-item').forEach(function(n) { n.classList.remove('active'); });
  var pageEl = document.getElementById('page' + page.charAt(0).toUpperCase() + page.slice(1));
  if (pageEl) { pageEl.classList.add('active'); pageEl.classList.add('fade-in'); }
  var navEl = document.querySelector('.nav-item[data-page="' + page + '"]');
  if (navEl) navEl.classList.add('active');
  var titles = { dashboard:'My Garden Side', beds:t('nav_beds'), crops:t('nav_crops'), today:t('nav_today'), calendar:t('nav_calendar'), planning:t('nav_planning'), analysis:t('nav_analysis'), settings:t('nav_settings'), ai:t('nav_ai'), veggieref:t('nav_veggieref'), garden:t('nav_garden') };
  document.getElementById('headerTitle').textContent = titles[page] || 'My Garden Side';
  document.getElementById('headerBack').classList.remove('visible');
  document.getElementById('headerSeason').textContent = getAppState('currentSeason');
  var fabPages = ['beds','crops'];
  document.getElementById('fab').style.display = fabPages.indexOf(page) >= 0 ? 'flex' : 'none';
  renderPage(page);
  refreshNavLabels();
  if (push) history.pushState({ page: page }, '', '#' + page);
  else history.replaceState({ page: page }, '', '#' + page);
  window.scrollTo(0, 0);
}
function goBack() {
  history.back();
}
window.addEventListener('popstate', function(e) {
  var st = e.state || {};
  if (st.detail) {
    currentPage = st.page || 'beds';
    detailView = st.detail;
    renderPage(currentPage);
    document.getElementById('headerBack').classList.add('visible');
    document.getElementById('fab').style.display = 'none';
  } else if (st.page) {
    navigate(st.page, false);
  } else {
    navigate('dashboard', false);
  }
});
function handleFab() {
  if (currentPage === 'beds') openBedModal();
  else if (currentPage === 'crops') openCropModal();
}
// ========== RENDER DISPATCH ==========
function renderPage(page) {
  refreshCropStatuses();

  switch(page) {
    case 'dashboard': renderDashboard(); break;
    case 'beds': detailView ? renderBedDetail(detailView) : renderBeds(); break;
    case 'crops': renderCrops(); break;
    case 'today': renderToday(); break;
    case 'calendar': renderCalendar(); break;
    case 'planning': renderPlanning(); break;
    case 'analysis': renderAnalysis(); break;
    case 'settings': renderSettings(); break;
    case 'ai': renderAi(); break;
    case 'veggieref': renderVeggieRef(); break;
    case 'garden': renderGarden(); break;
  }
}

// ========== MODAL SYSTEM ==========
var _modalOpenTime = 0;
function openModal(html) {
  document.getElementById('modalContent').innerHTML = html;
  document.getElementById('modalOverlay').classList.add('active');
  document.body.style.overflow = 'hidden';
  _modalOpenTime = Date.now();
}
function closeModal() {
  document.getElementById('modalOverlay').classList.remove('active');
  document.body.style.overflow = '';
}
function closeModalOverlay(e) {
  if (Date.now() - _modalOpenTime < 900) return;
  if (document.querySelector('#modalContent input, #modalContent textarea, #modalContent select')) return;
  if (e.target === document.getElementById('modalOverlay')) closeModal();
}
// ========== NAV LABELS (i18n) ==========
function refreshNavLabels() {
  document.querySelectorAll('[data-i18n]').forEach(function(el) {
    var key = el.getAttribute('data-i18n');
    if (key) el.textContent = t(key);
  });
  document.querySelectorAll('[data-i18n-title]').forEach(function(el) {
    var key = el.getAttribute('data-i18n-title');
    if (key) el.title = t(key);
  });
}

// ========== LANGUAGE SWITCH ==========
function changeLanguage(lang) {
  updateAppState('language', lang);              // persists via official API, no Proxy
  document.documentElement.lang = lang;          // update <html lang="…">
  refreshNavLabels();                             // update static [data-i18n] elements
  navigate(currentPage || 'settings');            // full re-render of visible page
}

// ========== INIT ==========
loadData();
// Calcul automatique du profil climatique si absent (appel silencieux en arrière-plan)
if (!getAppState('climate') && (getAppState('location') || {}).lat) {
  if (typeof ClimateModule !== 'undefined') ClimateModule.refresh(function() {});
}
cleanOrphanVeggies();
refreshCropStatuses();
pruneOrphanHistory();
rebuildLearningMemory();
document.documentElement.lang = getAppState('language') || 'fr';
refreshNavLabels();
var _settings = getAppState('settings') || {};
if (!_settings.languageChosen) {
  navigate('dashboard', false);
  renderLanguagePicker();
} else if (shouldShowOnboarding()) {
  navigate('dashboard', false);
  renderOnboarding();
} else {
  navigate('dashboard', false);
}
// ---- Masquer le splash screen ----
(function() {
  var sp = document.getElementById('splashScreen');
  if (!sp) return;
  setTimeout(function() {
    sp.classList.add('hiding');
    setTimeout(function() { if (sp.parentNode) sp.parentNode.removeChild(sp); }, 520);
  }, 380);
}());

;
/**
 * Green Vibes — modules/export.js
 * Fonctions d'export canoniques.
 *
 * Fonctions exposées :
 *   exportAppData()      — JSON complet incluant historique + mémoire IA (CANONICAL)
 *   exportData()         — JSON léger (APP uniquement, défini dans settings.js)
 *   exportHarvestsCSV()  — CSV des récoltes (nom, bac, date, kg réel, kg estimé)
 *   exportAnalysisCSV()  — CSV de la performance par légume et par bac
 *
 * Dépend de : APP, loadHistory(), loadLearningMemory(), loadNotifStore()
 * (toutes définies dans les modules existants)
 */

// ============================================================
// HELPER INTERNE — téléchargement générique
// ============================================================
function _gvpDownload(content, filename, mimeType) {
  var blob = new Blob([content], { type: mimeType });
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href     = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

// ============================================================
// HELPER INTERNE — construire une ligne CSV propre
// ============================================================
function _csvRow(fields) {
  return fields.map(function(f) {
    var s = String(f === null || f === undefined ? '' : f);
    // Échapper guillemets et encapsuler si nécessaire
    if (s.indexOf(',') >= 0 || s.indexOf('"') >= 0 || s.indexOf('\n') >= 0) {
      s = '"' + s.replace(/"/g, '""') + '"';
    }
    return s;
  }).join(',');
}

// ============================================================
// 1. EXPORT JSON COMPLET (fonction canonique)
// Inclut APP + historique récoltes + mémoire IA + notifications
// ============================================================
/**
 * Exporte un snapshot complet de l'application au format JSON.
 * Inclut : APP, gvp_history, gvp_learning_memory, gvp_notif_store.
 * Fichier nommé : my-garden-side-full-YYYY-MM-DD.json
 * Appelée par : settings.js (bouton "Export complet"), pwa.js
 */
function exportAppData() {
  var today = new Date().toISOString().split('T')[0];

  var payload = {
    _meta: {
      version:    '22',
      exportedAt: new Date().toISOString(),
      appName:    'My Garden Side',
      exportType: 'full'
    },
    // État principal de l'application
    app: {
      beds:          APP.beds,
      crops:         APP.crops,
      vegetables:    APP.vegetables,
      seasons:       APP.seasons,
      currentSeason: APP.currentSeason,
      location:      APP.location,
      settings:      APP.settings,
      language:      APP.language,
      userProfile:   APP.userProfile,
      completedTasks: APP.completedTasks
    },
    // Historique persistant des récoltes (gvp_history)
    harvestHistory: (function() {
      try { return typeof loadHistory === 'function' ? loadHistory() : []; }
      catch(e) { return []; }
    })(),
    // Mémoire d'apprentissage IA (gvp_learning_memory)
    learningMemory: (function() {
      try { return typeof loadLearningMemory === 'function' ? loadLearningMemory() : null; }
      catch(e) { return null; }
    })(),
    // Historique notifications (gvp_notif_store)
    notificationsStore: (function() {
      try { return typeof loadNotifStore === 'function' ? loadNotifStore() : null; }
      catch(e) { return null; }
    })()
  };

  var json = JSON.stringify(payload, null, 2);
  _gvpDownload(json, 'my-garden-side-full-' + today + '.json', 'application/json');
}

// ============================================================
// 2. EXPORT RÉCOLTES CSV
// Une ligne par culture récoltée, toutes saisons confondues
// ============================================================
/**
 * Exporte toutes les récoltes en CSV.
 * Colonnes : Saison, Légume, Bac, Planté le, Récolté prévu, Estimé (kg), Réel (kg), Performance (%)
 */
function exportHarvestsCSV() {
  var today   = new Date().toISOString().split('T')[0];
  var headers = ['Saison','Legume','Famille','Espace','Plante le','Recolte prevue','Estime (kg)','Reel (kg)','Performance (%)'];
  var rows    = [_csvRow(headers)];

  // Cultures récoltées dans APP
  var harvested = APP.crops.filter(function(c) { return c.status === 'harvested'; });
  harvested.forEach(function(c) {
    var veg  = APP.vegetables[c.veggieId];
    var bed  = APP.beds.find(function(b) { return b.id === c.bedId; });
    var est  = typeof getCropEstimatedYield === 'function' ? getCropEstimatedYield(c) : 0;
    var real = c.yieldReal || 0;
    var perf = est > 0 ? Math.round((real / est) * 100) : '';
    rows.push(_csvRow([
      c.season || '',
      veg ? veg.name : '?',
      veg ? (veg.family || '') : '',
      bed ? bed.name : 'Sans espace',
      c.datePlant || '',
      c.dateHarvest || '',
      est.toFixed(2),
      real.toFixed(2),
      perf
    ]));
  });

  // Ajouter aussi l'historique persistant si disponible
  if (typeof loadHistory === 'function') {
    var hist = loadHistory();
    hist.forEach(function(entry) {
      // Éviter les doublons avec les entrées APP déjà ajoutées
      var alreadyIn = harvested.some(function(c) { return c.id === entry.cropId; });
      if (alreadyIn) return;
      var est  = entry.estimatedYield || 0;
      var real = entry.realYield || 0;
      var perf = est > 0 ? Math.round((real / est) * 100) : '';
      rows.push(_csvRow([
        entry.season || '',
        entry.veggieName || '',
        entry.veggieFamily || '',
        entry.bedName || 'Sans espace',
        entry.datePlant || '',
        entry.dateHarvest || '',
        (typeof est  === 'number' ? est.toFixed(2)  : '0.00'),
        (typeof real === 'number' ? real.toFixed(2) : '0.00'),
        perf
      ]));
    });
  }

  _gvpDownload(rows.join('\n'), 'my-garden-side-recoltes-' + today + '.csv', 'text/csv;charset=utf-8;');
}

// ============================================================
// 3. EXPORT ANALYSE CSV
// Performance par légume et par bac, toutes saisons confondues
// ============================================================
/**
 * Exporte deux tableaux de performance en CSV :
 * - Performance par légume (rendement moyen, nb récoltes)
 * - Performance par bac (occupation, récoltes totales)
 */
function exportAnalysisCSV() {
  var today  = new Date().toISOString().split('T')[0];
  var output = '';

  // ---- Tableau 1 : par légume ----
  output += 'PERFORMANCE PAR LEGUME\n';
  output += _csvRow(['Legume','Famille','Nb recoltes','Rendement estime total (kg)','Rendement reel total (kg)','Performance moy. (%)']) + '\n';

  var byVeggie = {};
  APP.crops.filter(function(c) { return c.status === 'harvested'; }).forEach(function(c) {
    var veg = APP.vegetables[c.veggieId]; if (!veg) return;
    if (!byVeggie[c.veggieId]) byVeggie[c.veggieId] = { name: veg.name, family: veg.family || '', estTotal: 0, realTotal: 0, count: 0 };
    var est = typeof getCropEstimatedYield === 'function' ? getCropEstimatedYield(c) : 0;
    byVeggie[c.veggieId].estTotal  += est;
    byVeggie[c.veggieId].realTotal += (c.yieldReal || 0);
    byVeggie[c.veggieId].count++;
  });

  Object.values(byVeggie).sort(function(a, b) { return b.realTotal - a.realTotal; }).forEach(function(v) {
    var perf = v.estTotal > 0 ? Math.round((v.realTotal / v.estTotal) * 100) : '';
    output += _csvRow([v.name, v.family, v.count, v.estTotal.toFixed(2), v.realTotal.toFixed(2), perf]) + '\n';
  });

  output += '\n';

  // ---- Tableau 2 : par bac ----
  output += 'PERFORMANCE PAR ESPACE\n';
  output += _csvRow(['Espace','Surface (m2)','Nb recoltes','Rendement reel total (kg)','Occupation actuelle (%)']) + '\n';

  APP.beds.forEach(function(bed) {
    var recoltes = APP.crops.filter(function(c) { return c.bedId === bed.id && c.status === 'harvested'; });
    var surf     = typeof getBedSurface === 'function' ? getBedSurface(bed) : (bed.length * bed.width);
    var occ      = typeof getBedOccupation === 'function' ? getBedOccupation(bed) : 0;
    var realKg   = recoltes.reduce(function(s, c) { return s + (c.yieldReal || 0); }, 0);
    output += _csvRow([bed.name, surf.toFixed(2), recoltes.length, realKg.toFixed(2), occ]) + '\n';
  });

  _gvpDownload(output, 'my-garden-side-analyse-' + today + '.csv', 'text/csv;charset=utf-8;');
}
;
/**
 * Green Vibes — modules/backup.js
 * Système de sauvegardes locales automatiques dans localStorage.
 *
 * Fonctions exposées :
 *   createLocalBackup(label)  — crée une sauvegarde nommée (max 5 gardées)
 *   restoreLatestBackup()     — restaure la sauvegarde la plus récente
 *   restoreBackup(index)      — restaure une sauvegarde spécifique (0 = plus récente)
 *   listBackups()             — retourne [{index, label, date, size}]
 *   deleteBackup(index)       — supprime une sauvegarde
 *
 * Stockage : localStorage clé 'gvp_backups'
 *   Format : tableau d'objets { id, label, date, snapshot }
 *   Maximum 5 sauvegardes — la plus ancienne est supprimée automatiquement.
 *
 * Dépend de : APP, saveData() (dans storage.js), navigate()
 */

var GVP_BACKUP_KEY  = 'gvp_backups';
var GVP_BACKUP_MAX  = 5;

// ---- Lecture / écriture du store de backups ----
function _loadBackupStore() {
  try {
    var raw = localStorage.getItem(GVP_BACKUP_KEY);
    return raw ? JSON.parse(raw) : [];
  } catch(e) {
    return [];
  }
}

function _saveBackupStore(store) {
  try {
    localStorage.setItem(GVP_BACKUP_KEY, JSON.stringify(store));
    return true;
  } catch(e) {
    console.error('GVP Backup — erreur localStorage:', e);
    return false;
  }
}

// ---- Snapshot complet de l'état courant ----
function _buildSnapshot() {
  return {
    app: JSON.parse(JSON.stringify(APP)),  // deep clone de l'état APP
    harvestHistory: (function() {
      try { return typeof loadHistory === 'function' ? loadHistory() : []; }
      catch(e) { return []; }
    })(),
    learningMemory: (function() {
      try { return typeof loadLearningMemory === 'function' ? loadLearningMemory() : null; }
      catch(e) { return null; }
    })(),
    notificationsStore: (function() {
      try { return typeof loadNotifStore === 'function' ? loadNotifStore() : null; }
      catch(e) { return null; }
    })()
  };
}

// ============================================================
// createLocalBackup(label)
// Crée une nouvelle sauvegarde. Supprime la plus ancienne si > MAX.
// label : chaîne libre (ex: "avant saison 2026", "sauvegarde manuelle")
// ============================================================
function createLocalBackup(label) {
  var store    = _loadBackupStore();
  var snapshot = _buildSnapshot();
  var now      = new Date();

  var appData = snapshot.app || snapshot.data || {};
  var entry = {
    id:       'bkp_' + now.getTime(),
    label:    label || 'Sauvegarde du ' + fmtDate(now),
    date:     now.toISOString(),
    dateStr:  fmtDate(now) + ' ' + now.toLocaleTimeString((typeof getAppState === 'function' && getAppState('language') === 'en') ? 'en-GB' : 'fr-FR', { hour: '2-digit', minute: '2-digit' }),
    beds:     (appData.beds || []).length,
    crops:    (appData.crops || []).length,
    season:   appData.currentSeason || '?',
    snapshot: snapshot
  };

  // Ajouter en tête (la plus récente en premier)
  store.unshift(entry);

  // Garder max GVP_BACKUP_MAX sauvegardes
  if (store.length > GVP_BACKUP_MAX) {
    store = store.slice(0, GVP_BACKUP_MAX);
  }

  var ok = _saveBackupStore(store);
  if (ok) {
    alert('✅ Sauvegarde créée : ' + entry.label);
  } else {
    alert('❌ Erreur lors de la sauvegarde. localStorage peut être plein.');
  }
  return ok;
}

// ============================================================
// listBackups()
// Retourne la liste des sauvegardes sans les snapshots (léger).
// ============================================================
function listBackups() {
  var store = _loadBackupStore();
  return store.map(function(entry, idx) {
    return {
      index:   idx,
      id:      entry.id,
      label:   entry.label,
      dateStr: entry.dateStr || entry.date,
      date:    entry.date,
      beds:    entry.beds || 0,
      crops:   entry.crops || 0,
      season:  entry.season || '?'
    };
  });
}

// ============================================================
// restoreBackup(index)
// Restaure la sauvegarde à l'index donné (0 = la plus récente).
// ============================================================
function restoreBackup(index) {
  var store = _loadBackupStore();
  if (!store[index]) {
    alert('❌ Aucune sauvegarde trouvée à l\'index ' + index);
    return false;
  }

  var entry    = store[index];
  var snapshot = entry.snapshot;
  if (!snapshot || !snapshot.app) {
    alert('❌ Sauvegarde corrompue.');
    return false;
  }

  if (!confirm('Restaurer "' + entry.label + '" du ' + entry.dateStr + ' ?\n\nL\'état actuel sera remplacé.')) {
    return false;
  }

  try {
    // Restaurer APP avec validation des types critiques
    var appData = snapshot.app;
    Object.keys(appData).forEach(function(key) {
      APP[key] = appData[key];
    });
    // Garantir que les tableaux critiques restent des tableaux
    if (!Array.isArray(APP.beds))                 APP.beds                 = [];
    if (!Array.isArray(APP.crops))                APP.crops                = [];
    if (!Array.isArray(APP.completedTasks))       APP.completedTasks       = [];
    if (!Array.isArray(APP.notificationsRead))    APP.notificationsRead    = [];
    if (!Array.isArray(APP.notificationsIgnored)) APP.notificationsIgnored = [];
    if (typeof APP.vegetables !== 'object' || Array.isArray(APP.vegetables)) APP.vegetables = {};
    saveData();

    // Restaurer l'historique si disponible
    if (snapshot.harvestHistory && typeof saveHistory === 'function') {
      saveHistory(snapshot.harvestHistory);
    }

    // Restaurer la mémoire IA si disponible
    if (snapshot.learningMemory && typeof saveLearningMemory === 'function') {
      saveLearningMemory(snapshot.learningMemory);
    }

    // Restaurer les notifications si disponible
    if (snapshot.notificationsStore && typeof saveNotifStore === 'function') {
      saveNotifStore(snapshot.notificationsStore);
    }

    // Recharger l'application proprement
    if (typeof navigate === 'function') {
      navigate('dashboard');
    } else {
      window.location.reload();
    }

    alert('✅ Restauration réussie : ' + entry.label);
    return true;
  } catch(e) {
    console.error('GVP Backup — erreur restauration:', e);
    alert('❌ Erreur lors de la restauration : ' + e.message);
    return false;
  }
}

// ============================================================
// restoreLatestBackup()
// Raccourci — restaure la sauvegarde la plus récente (index 0).
// ============================================================
function restoreLatestBackup() {
  return restoreBackup(0);
}

// ============================================================
// deleteBackup(index)
// Supprime la sauvegarde à l'index donné.
// ============================================================
function deleteBackup(index) {
  var store = _loadBackupStore();
  if (!store[index]) return false;
  var label = store[index].label;
  if (!confirm('Supprimer la sauvegarde "' + label + '" ?')) return false;
  store.splice(index, 1);
  _saveBackupStore(store);
  return true;
}

// ============================================================
// renderBackupPanel()
// Génère le HTML du panneau de sauvegardes pour les Réglages.
// Appelable depuis settings.js sans modifier ce fichier.
// ============================================================
function renderBackupPanel() {
  var backups = listBackups();
  var html = '<div class="section-title">\uD83D\uDCBE Sauvegardes locales</div>';

  html += '<div class="card" style="padding:14px 16px;">';

  // Bouton créer
  html += '<button class="btn btn-secondary btn-block" style="margin-bottom:10px;" ' +
    'onclick="createLocalBackup(\'\')">' +
    '\uD83D\uDCBE Créer une sauvegarde maintenant</button>';

  if (backups.length === 0) {
    html += '<div style="text-align:center;color:var(--text-light);font-size:0.82rem;padding:10px 0;">Aucune sauvegarde</div>';
  } else {
    html += '<div style="font-size:0.72rem;color:var(--text-light);margin-bottom:8px;">' +
      backups.length + '/' + GVP_BACKUP_MAX + ' sauvegarde' + (backups.length > 1 ? 's' : '') +
      ' — la plus ancienne est supprimée automatiquement</div>';

    backups.forEach(function(b) {
      html +=
        '<div style="display:flex;align-items:center;gap:8px;padding:8px 0;border-bottom:1px solid #f3f4f6;">' +
          '<div style="flex:1;min-width:0;">' +
            '<div style="font-size:0.82rem;font-weight:600;color:var(--text);">' + escH(b.label) + '</div>' +
            '<div style="font-size:0.7rem;color:var(--text-light);">' +
              b.dateStr + ' \u00B7 ' + b.beds + ' espace' + (b.beds !== 1 ? 's' : '') +
              ' \u00B7 ' + b.crops + ' culture' + (b.crops !== 1 ? 's' : '') +
              ' \u00B7 Saison ' + b.season +
            '</div>' +
          '</div>' +
          '<button class="btn btn-sm btn-secondary" onclick="restoreBackup(' + b.index + ')">Restaurer</button>' +
          '<button class="btn btn-sm btn-danger" onclick="deleteBackup(' + b.index + ');renderSettings()">🗑</button>' +
        '</div>';
    });
  }

  html += '</div>';
  return html;
}
